from dataclasses import dataclass

@dataclass
class SBTiMilestoneTracker:
    base_year: int
    base_year_scope2_tco2e: float      # Total Scope 2 in base year
    ai_share_of_scope2: float          # Fraction attributable to AI workloads at base year
    target_reduction_pct: float = 0.42 # 42% by 2030 (1.5°C pathway)
    target_year: int = 2030

    def ai_base_tco2e(self) -> float:
        return self.base_year_scope2_tco2e * self.ai_share_of_scope2

    def ai_target_tco2e(self) -> float:
        return self.ai_base_tco2e() * (1.0 - self.target_reduction_pct)

    def annual_reduction_rate(self) -> float:
        years = self.target_year - self.base_year
        return 1.0 - ((1.0 - self.target_reduction_pct) ** (1.0 / years))

    def year_milestone(self, year: int) -> float:
        """Expected tCO₂e for the AI workload in the given year."""
        elapsed = year - self.base_year
        return self.ai_base_tco2e() * ((1.0 - self.annual_reduction_rate()) ** elapsed)

    def is_on_track(self, year: int, actual_tco2e: float) -> bool:
        return actual_tco2e <= self.year_milestone(year)

# Example
tracker = SBTiMilestoneTracker(
    base_year=2022,
    base_year_scope2_tco2e=5000.0,   # 5,000 tCO₂e total Scope 2
    ai_share_of_scope2=0.30,          # AI is 30% of Scope 2
)
for y in [2024, 2025, 2026, 2027, 2028, 2029, 2030]:
    print(f"{y}: AI milestone {tracker.year_milestone(y):.0f} tCO₂e")
# 2024: 1352 tCO₂e
# 2030: 870 tCO₂e (42% reduction from 1500 base)
